    27  import javax.security.sasl.SaslException;
    28
    29  /**
    30   * SCRAM request/response message creation and parsing based on
    31   * <a href="https://tools.ietf.org/html/rfc5802">RFC 5802</a>
    32   *
    33   */
    34  public class ScramMessages {
    35
    36      abstract static class AbstractScramMessage {
    37
    38          static final String ALPHA = "[A-Za-z]+";
    39          static final String VALUE_SAFE = "[\\x01-\\x7F&&[^=,]]+";
    40          static final String VALUE = "[\\x01-\\x7F&&[^,]]+";
    41          static final String PRINTABLE = "[\\x21-\\x7E&&[^,]]+";
    42          static final String SASLNAME = "(?:[\\x01-\\x7F&&[^=,]]|=2C|=3D)+";
    43          static final String BASE64_CHAR = "[a-zA-Z0-9/+]";
    44          static final String BASE64 = String.format("(?:%s{4})*(?:%s{3}=|%s{2}==)?", BASE64_CHAR, BASE64_CHAR, BASE64_CHAR);
    45          static final String RESERVED = String.format("(m=%s,)?", VALUE);
    46          static final String EXTENSIONS = String.format("(,%s=%s)*", ALPHA, VALUE);
    47
    48          abstract String toMessage();
    49
    50          public byte[] toBytes() {
    51              return toMessage().getBytes(StandardCharsets.UTF_8);
    52          }
    53
    54          protected String toMessage(byte[] messageBytes) {
    55              return new String(messageBytes, StandardCharsets.UTF_8);
    56          }
    57      }
    58
    59      /**
    60       * Format:
    61       *     gs2-header [reserved-mext ","] username "," nonce ["," extensions]
    62       * Limitations:
    63       *     Only gs2-header "n" is supported.
    64       *     Extensions are ignored.
    65       *
    66       */
    67      public static class ClientFirstMessage extends AbstractScramMessage {
    68          private static final Pattern PATTERN = Pattern.compile(String.format(
    69                  "n,(a=(?<authzid>%s))?,%sn=(?<saslname>%s),r=(?<nonce>%s)(?<extensions>%s)",
    70                  SASLNAME,
    71                  RESERVED,
    72                  SASLNAME,
    73                  PRINTABLE,
    74                  EXTENSIONS));
    75
    76
    77          private final String saslName;
    78          private final String nonce;
    79          private final String authorizationId;
    80          private final ScramExtensions extensions;
    81          public ClientFirstMessage(byte[] messageBytes) throws SaslException {
    82              String message = toMessage(messageBytes);
    83              Matcher matcher = PATTERN.matcher(message);
    84              if (!matcher.matches())
    85                  throw new SaslException("Invalid SCRAM client first message format: " + message);
    86              String authzid = matcher.group("authzid");
    87              this.authorizationId = authzid != null ? authzid : "";
    88              this.saslName = matcher.group("saslname");
    89              this.nonce = matcher.group("nonce");
    90              String extString = matcher.group("extensions");
    91
    92              this.extensions = extString.startsWith(",") ? new ScramExtensions(extString.substring(1)) : new ScramExtensions();
    93          }
    94          public ClientFirstMessage(String saslName, String nonce, Map<String, String> extensions) {
    95              this.saslName = saslName;
    96              this.nonce = nonce;
    97              this.extensions = new ScramExtensions(extensions);
    98              this.authorizationId = ""; // Optional authzid not specified in gs2-header
    99          }
   100          public String saslName() {
   101              return saslName;
   102          }
   103          public String nonce() {
   104              return nonce;
   105          }
   106          public String authorizationId() {
   107              return authorizationId;
   108          }
   109          public String gs2Header() {
   110              return "n," + authorizationId + ",";
   111          }
   112          public ScramExtensions extensions() {
   113              return extensions;
   114          }
   115
   116          public String clientFirstMessageBare() {
   117              String extensionStr = Utils.mkString(extensions.map(), "", "", "=", ",");
   118
   119              if (extensionStr.isEmpty())
   120                  return String.format("n=%s,r=%s", saslName, nonce);
   121              else
   122                  return String.format("n=%s,r=%s,%s", saslName, nonce, extensionStr);
   123          }
   124          String toMessage() {
   125              return gs2Header() + clientFirstMessageBare();
   126          }
   127      }
   128
   129      /**
   130       * Format:
   131       *     [reserved-mext ","] nonce "," salt "," iteration-count ["," extensions]
   132       * Limitations:
   133       *     Extensions are ignored.
   134       *
   135       */
   136      public static class ServerFirstMessage extends AbstractScramMessage {
   137          private static final Pattern PATTERN = Pattern.compile(String.format(
   138                  "%sr=(?<nonce>%s),s=(?<salt>%s),i=(?<iterations>[0-9]+)%s",
   139                  RESERVED,
   140                  PRINTABLE,
   141                  BASE64,
   142                  EXTENSIONS));
   143
   144          private final String nonce;
   145          private final byte[] salt;
   146          private final int iterations;
   147          public ServerFirstMessage(byte[] messageBytes) throws SaslException {
   148              String message = toMessage(messageBytes);
   149              Matcher matcher = PATTERN.matcher(message);
   150              if (!matcher.matches())
   151                  throw new SaslException("Invalid SCRAM server first message format: " + message);
   152              try {
   153                  this.iterations = Integer.parseInt(matcher.group("iterations"));
   154                  if (this.iterations <= 0)
   155                      throw new SaslException("Invalid SCRAM server first message format: invalid iterations " + iterations);
   156              } catch (NumberFormatException e) {
   157                  throw new SaslException("Invalid SCRAM server first message format: invalid iterations", e);
   158              }
   159              this.nonce = matcher.group("nonce");
   160              String salt = matcher.group("salt");
   161              this.salt = Base64.getDecoder().decode(salt);
   162          }
   163          public ServerFirstMessage(String clientNonce, String serverNonce, byte[] salt, int iterations) {
   164              this.nonce = clientNonce + serverNonce;
   165              this.salt = salt;
   166              this.iterations = iterations;
   167          }
   168          public String nonce() {
   169              return nonce;
   170          }
   171          public byte[] salt() {
   172              return salt;
   173          }
   174          public int iterations() {
   175              return iterations;
   176          }
   177          String toMessage() {
   178              return String.format("r=%s,s=%s,i=%d", nonce, Base64.getEncoder().encodeToString(salt), iterations);
   179          }
   180      }
   181      /**
   182       * Format:
   183       *     channel-binding "," nonce ["," extensions]"," proof
   184       * Limitations:
   185       *     Extensions are ignored.
   186       *
   187       */
   188      public static class ClientFinalMessage extends AbstractScramMessage {
   189          private static final Pattern PATTERN = Pattern.compile(String.format(
   190                  "c=(?<channel>%s),r=(?<nonce>%s)%s,p=(?<proof>%s)",
   191                  BASE64,
   192                  PRINTABLE,
   193                  EXTENSIONS,
   194                  BASE64));
   195
   196          private final byte[] channelBinding;
   197          private final String nonce;
   198          private byte[] proof;
   199          public ClientFinalMessage(byte[] messageBytes) throws SaslException {
   200              String message = toMessage(messageBytes);
   201              Matcher matcher = PATTERN.matcher(message);
   202              if (!matcher.matches())
   203                  throw new SaslException("Invalid SCRAM client final message format: " + message);
   204
   205              this.channelBinding = Base64.getDecoder().decode(matcher.group("channel"));
   206              this.nonce = matcher.group("nonce");
   207              this.proof = Base64.getDecoder().decode(matcher.group("proof"));
   208          }
   209          public ClientFinalMessage(byte[] channelBinding, String nonce) {
   210              this.channelBinding = channelBinding;
   211              this.nonce = nonce;
   212          }
   213          public byte[] channelBinding() {
   214              return channelBinding;
   215          }
   216          public String nonce() {
   217              return nonce;
   218          }
   219          public byte[] proof() {
   220              return proof;
   221          }
   222          public void proof(byte[] proof) {
   223              this.proof = proof;
   224          }
   225          public String clientFinalMessageWithoutProof() {
   226              return String.format("c=%s,r=%s",
   227                      Base64.getEncoder().encodeToString(channelBinding),
   228                      nonce);
   229          }
   230          String toMessage() {
   231              return String.format("%s,p=%s",
   232                      clientFinalMessageWithoutProof(),
   233                      Base64.getEncoder().encodeToString(proof));
   234          }
   235      }
   236      /**
   237       * Format:
   238       *     ("e=" server-error-value | "v=" base64_server_signature) ["," extensions]
   239       * Limitations:
   240       *     Extensions are ignored.
   241       *
   242       */
   243      public static class ServerFinalMessage extends AbstractScramMessage {
   244          private static final Pattern PATTERN = Pattern.compile(String.format(
   245                  "(?:e=(?<error>%s))|(?:v=(?<signature>%s))%s",
   246                  VALUE_SAFE,
   247                  BASE64,
   248                  EXTENSIONS));
   249
   250          private final String error;
   251          private final byte[] serverSignature;
   252          public ServerFinalMessage(byte[] messageBytes) throws SaslException {
   253              String message = toMessage(messageBytes);
   254              Matcher matcher = PATTERN.matcher(message);
   255              if (!matcher.matches())
   256                  throw new SaslException("Invalid SCRAM server final message format: " + message);
   257              String error = null;
   258              try {
   259                  error = matcher.group("error");
   260              } catch (IllegalArgumentException e) {
   261                  // ignore
   262              }
   263              if (error == null) {
   264                  this.serverSignature = Base64.getDecoder().decode(matcher.group("signature"));
   265                  this.error = null;
   266              } else {
   267                  this.serverSignature = null;
   268                  this.error = error;
   269              }
   270          }
   271          public ServerFinalMessage(String error, byte[] serverSignature) {
   272              this.error = error;
   273              this.serverSignature = serverSignature;
   274          }
   275          public String error() {
   276              return error;
   277          }
   278          public byte[] serverSignature() {
   279              return serverSignature;
   280          }
   281          String toMessage() {
   282              if (error != null)
   283                  return "e=" + error;
   284              else
   285                  return "v=" + Base64.getEncoder().encodeToString(serverSignature);
   286          }
   287      }
   288  }

