    45  /**
    46   * {@code SaslServer} implementation for SASL/OAUTHBEARER in Kafka. An instance
    47   * of {@link OAuthBearerToken} is available upon successful authentication via
    48   * the negotiated property "{@code OAUTHBEARER.token}"; the token could be used
    49   * in a custom authorizer (to authorize based on JWT claims rather than ACLs,
    50   * for example).
    51   */
    52  public class OAuthBearerSaslServer implements SaslServer {
    53
    54      private static final Logger log = LoggerFactory.getLogger(OAuthBearerSaslServer.class);
    55      private static final String NEGOTIATED_PROPERTY_KEY_TOKEN = OAuthBearerLoginModule.OAUTHBEARER_MECHANISM + ".token";
    56      private static final String INTERNAL_ERROR_ON_SERVER = "Authentication could not be performed due to an internal error on the server";
    57
    58      private final AuthenticateCallbackHandler callbackHandler;
    59
    60      private boolean complete;
    61      private OAuthBearerToken tokenForNegotiatedProperty = null;
    62      private String errorMessage = null;
    63      private SaslExtensions extensions;
    64
    65      public OAuthBearerSaslServer(CallbackHandler callbackHandler) {
    66          if (!(Objects.requireNonNull(callbackHandler) instanceof AuthenticateCallbackHandler))
    67              throw new IllegalArgumentException(String.format("Callback handler must be castable to %s: %s",
    68                      AuthenticateCallbackHandler.class.getName(), callbackHandler.getClass().getName()));
    69          this.callbackHandler = (AuthenticateCallbackHandler) callbackHandler;
    70      }
    71
    72      /**
    73       * @throws SaslAuthenticationException
    74       *             if access token cannot be validated
    75       *             <p>
    76       *             <b>Note:</b> This method may throw
    77       *             {@link SaslAuthenticationException} to provide custom error
    78       *             messages to clients. But care should be taken to avoid including
    79       *             any information in the exception message that should not be
    80       *             leaked to unauthenticated clients. It may be safer to throw
    81       *             {@link SaslException} in some cases so that a standard error
    82       *             message is returned to clients.
    83       *             </p>
    84       */
    85      @Override
    86      public byte[] evaluateResponse(byte[] response) throws SaslException, SaslAuthenticationException {
    87          if (response.length == 1 && response[0] == OAuthBearerSaslClient.BYTE_CONTROL_A && errorMessage != null) {
    88              log.debug("Received %x01 response from client after it received our error");
    89              throw new SaslAuthenticationException(errorMessage);
    90          }
    91          errorMessage = null;
    92
    93          OAuthBearerClientInitialResponse clientResponse;
    94          try {
    95              clientResponse = new OAuthBearerClientInitialResponse(response);
    96          } catch (SaslException e) {
    97              log.debug(e.getMessage());
    98              throw e;
    99          }
   100
   101          return process(clientResponse.tokenValue(), clientResponse.authorizationId(), clientResponse.extensions());
   102      }
   103
   104      @Override
   105      public String getAuthorizationID() {
   106          if (!complete)
   107              throw new IllegalStateException("Authentication exchange has not completed");
   108          return tokenForNegotiatedProperty.principalName();
   109      }
   110
   111      @Override
   112      public String getMechanismName() {
   113          return OAuthBearerLoginModule.OAUTHBEARER_MECHANISM;
   114      }
   115
   116      @Override
   117      public Object getNegotiatedProperty(String propName) {
   118          if (!complete)
   119              throw new IllegalStateException("Authentication exchange has not completed");
   120          if (NEGOTIATED_PROPERTY_KEY_TOKEN.equals(propName))
   121              return tokenForNegotiatedProperty;
   122          if (SaslInternalConfigs.CREDENTIAL_LIFETIME_MS_SASL_NEGOTIATED_PROPERTY_KEY.equals(propName))
   123              return tokenForNegotiatedProperty.lifetimeMs();
   124          return extensions.map().get(propName);
   125      }
   126
   127      @Override
   128      public boolean isComplete() {
   129          return complete;
   130      }
   131
   132      @Override
   133      public byte[] unwrap(byte[] incoming, int offset, int len) {
   134          if (!complete)
   135              throw new IllegalStateException("Authentication exchange has not completed");
   136          throw new IllegalStateException("OAUTHBEARER supports neither integrity nor privacy");
   137      }
   138
   139      @Override
   140      public byte[] wrap(byte[] outgoing, int offset, int len) {
   141          if (!complete)
   142              throw new IllegalStateException("Authentication exchange has not completed");
   143          throw new IllegalStateException("OAUTHBEARER supports neither integrity nor privacy");
   144      }
   145
   146      @Override
   147      public void dispose() {
   148          complete = false;
   149          tokenForNegotiatedProperty = null;
   150          extensions = null;
   151      }
   152
   153      private byte[] process(String tokenValue, String authorizationId, SaslExtensions extensions) throws SaslException {
   154          OAuthBearerValidatorCallback callback = new OAuthBearerValidatorCallback(tokenValue);
   155          try {
   156              callbackHandler.handle(new Callback[] {callback});
   157          } catch (IOException | UnsupportedCallbackException e) {
   158              handleCallbackError(e);
   159          }
   160          OAuthBearerToken token = callback.token();
   161          if (token == null) {
   162              errorMessage = jsonErrorResponse(callback.errorStatus(), callback.errorScope(),
   163                      callback.errorOpenIDConfiguration());
   164              log.debug(errorMessage);
   165              return errorMessage.getBytes(StandardCharsets.UTF_8);
   166          }
   167          /*
   168           * We support the client specifying an authorization ID as per the SASL
   169           * specification, but it must match the principal name if it is specified.
   170           */
   171          if (!authorizationId.isEmpty() && !authorizationId.equals(token.principalName()))
   172              throw new SaslAuthenticationException(String.format(
   173                      "Authentication failed: Client requested an authorization id (%s) that is different from the token's principal name (%s)",
   174                      authorizationId, token.principalName()));
   175
   176          Map<String, String> validExtensions = processExtensions(token, extensions);
   177
   178          tokenForNegotiatedProperty = token;
   179          this.extensions = new SaslExtensions(validExtensions);
   180          complete = true;
   181          log.debug("Successfully authenticate User={}", token.principalName());
   182          return new byte[0];
   183      }
   184
   185      private Map<String, String> processExtensions(OAuthBearerToken token, SaslExtensions extensions) throws SaslException {
   186          OAuthBearerExtensionsValidatorCallback extensionsCallback = new OAuthBearerExtensionsValidatorCallback(token, extensions);
   187          try {
   188              callbackHandler.handle(new Callback[] {extensionsCallback});
   189          } catch (UnsupportedCallbackException e) {
   190              // backwards compatibility - no extensions will be added
   191          } catch (IOException e) {
   192              handleCallbackError(e);
   193          }
   194          if (!extensionsCallback.invalidExtensions().isEmpty()) {
   195              String errorMessage = String.format("Authentication failed: %d extensions are invalid! They are: %s",
   196                      extensionsCallback.invalidExtensions().size(),
   197                      Utils.mkString(extensionsCallback.invalidExtensions(), "", "", ": ", "; "));
   198              log.debug(errorMessage);
   199              throw new SaslAuthenticationException(errorMessage);
   200          }
   201
   202          return extensionsCallback.validatedExtensions();
   203      }
   204
   205      private static String jsonErrorResponse(String errorStatus, String errorScope, String errorOpenIDConfiguration) {
   206          String jsonErrorResponse = String.format("{\"status\":\"%s\"", errorStatus);
   207          if (errorScope != null)
   208              jsonErrorResponse = String.format("%s, \"scope\":\"%s\"", jsonErrorResponse, errorScope);
   209          if (errorOpenIDConfiguration != null)
   210              jsonErrorResponse = String.format("%s, \"openid-configuration\":\"%s\"", jsonErrorResponse,
   211                      errorOpenIDConfiguration);
   212          jsonErrorResponse = String.format("%s}", jsonErrorResponse);
   213          return jsonErrorResponse;
   214      }
   215
   216      private void handleCallbackError(Exception e) throws SaslException {
   217          String msg = String.format("%s: %s", INTERNAL_ERROR_ON_SERVER, e.getMessage());
   218          log.debug(msg, e);
   219          throw new SaslException(msg);
   220      }
   221
   222      public static String[] mechanismNamesCompatibleWithPolicy(Map<String, ?> props) {
   223          return props != null && "true".equals(String.valueOf(props.get(Sasl.POLICY_NOPLAINTEXT))) ? new String[] {}
   224                  : new String[] {OAuthBearerLoginModule.OAUTHBEARER_MECHANISM};
   225      }
   226
   227      public static class OAuthBearerSaslServerFactory implements SaslServerFactory {
   228          @Override
   229          public SaslServer createSaslServer(String mechanism, String protocol, String serverName, Map<String, ?> props,
   230                  CallbackHandler callbackHandler) {
   231              String[] mechanismNamesCompatibleWithPolicy = getMechanismNames(props);
   232              for (String name : mechanismNamesCompatibleWithPolicy) {
   233                  if (name.equals(mechanism)) {
   234                      return new OAuthBearerSaslServer(callbackHandler);
   235                  }
   236              }
   237              return null;
   238          }
   239
   240          @Override
   241          public String[] getMechanismNames(Map<String, ?> props) {
   242              return OAuthBearerSaslServer.mechanismNamesCompatibleWithPolicy(props);
   243          }
   244      }
   245  }

