    28  import javax.security.sasl.SaslException;
    29
    30  public class OAuthBearerClientInitialResponse {
    31      static final String SEPARATOR = "\u0001";
    32
    33      private static final String SASLNAME = "(?:[\\x01-\\x7F&&[^=,]]|=2C|=3D)+";
    34      private static final String KEY = "[A-Za-z]+";
    35      private static final String VALUE = "[\\x21-\\x7E \t\r\n]+";
    36
    37      private static final String KVPAIRS = String.format("(%s=%s%s)*", KEY, VALUE, SEPARATOR);
    38      private static final Pattern AUTH_PATTERN = Pattern.compile("(?<scheme>[\\w]+)[ ]+(?<token>[-_~+/\\.a-zA-Z0-9]+([=]*))");
    39      private static final Pattern CLIENT_INITIAL_RESPONSE_PATTERN = Pattern.compile(
    40              String.format("n,(a=(?<authzid>%s))?,%s(?<kvpairs>%s)%s", SASLNAME, SEPARATOR, KVPAIRS, SEPARATOR));
    41      public static final String AUTH_KEY = "auth";
    42
    43      private final String tokenValue;
    44      private final String authorizationId;
    45      private final SaslExtensions saslExtensions;
    46
    47      public static final Pattern EXTENSION_KEY_PATTERN = Pattern.compile(KEY);
    48      public static final Pattern EXTENSION_VALUE_PATTERN = Pattern.compile(VALUE);
    49
    50      public OAuthBearerClientInitialResponse(byte[] response) throws SaslException {
    51          String responseMsg = new String(response, StandardCharsets.UTF_8);
    52          Matcher matcher = CLIENT_INITIAL_RESPONSE_PATTERN.matcher(responseMsg);
    53          if (!matcher.matches())
    54              throw new SaslException("Invalid OAUTHBEARER client first message");
    55          String authzid = matcher.group("authzid");
    56          this.authorizationId = authzid == null ? "" : authzid;
    57          String kvPairs = matcher.group("kvpairs");
    58          Map<String, String> properties = Utils.parseMap(kvPairs, "=", SEPARATOR);
    59          String auth = properties.get(AUTH_KEY);
    60          if (auth == null)
    61              throw new SaslException("Invalid OAUTHBEARER client first message: 'auth' not specified");
    62          properties.remove(AUTH_KEY);
    63          SaslExtensions extensions = new SaslExtensions(properties);
    64          validateExtensions(extensions);
    65          this.saslExtensions = extensions;
    66
    67          Matcher authMatcher = AUTH_PATTERN.matcher(auth);
    68          if (!authMatcher.matches())
    69              throw new SaslException("Invalid OAUTHBEARER client first message: invalid 'auth' format");
    70          if (!"bearer".equalsIgnoreCase(authMatcher.group("scheme"))) {
    71              String msg = String.format("Invalid scheme in OAUTHBEARER client first message: %s",
    72                      matcher.group("scheme"));
    73              throw new SaslException(msg);
    74          }
    75          this.tokenValue = authMatcher.group("token");
    76      }
    77
    78      /**
    79       * Constructor
    80       *
    81       * @param tokenValue
    82       *            the mandatory token value
    83       * @param extensions
    84       *            the optional extensions
    85       * @throws SaslException
    86       *             if any extension name or value fails to conform to the required
    87       *             regular expression as defined by the specification, or if the
    88       *             reserved {@code auth} appears as a key
    89       */
    90      public OAuthBearerClientInitialResponse(String tokenValue, SaslExtensions extensions) throws SaslException {
    91          this(tokenValue, "", extensions);
    92      }
    93
    94      /**
    95       * Constructor
    96       *
    97       * @param tokenValue
    98       *            the mandatory token value
    99       * @param authorizationId
   100       *            the optional authorization ID
   101       * @param extensions
   102       *            the optional extensions
   103       * @throws SaslException
   104       *             if any extension name or value fails to conform to the required
   105       *             regular expression as defined by the specification, or if the
   106       *             reserved {@code auth} appears as a key
   107       */
   108      public OAuthBearerClientInitialResponse(String tokenValue, String authorizationId, SaslExtensions extensions) throws SaslException {
   109          this.tokenValue = Objects.requireNonNull(tokenValue, "token value must not be null");
   110          this.authorizationId = authorizationId == null ? "" : authorizationId;
   111          validateExtensions(extensions);
   112          this.saslExtensions = extensions != null ? extensions : SaslExtensions.empty();
   113      }
   114
   115      /**
   116       * Return the always non-null extensions
   117       *
   118       * @return the always non-null extensions
   119       */
   120      public SaslExtensions extensions() {
   121          return saslExtensions;
   122      }
   123
   124      public byte[] toBytes() {
   125          String authzid = authorizationId.isEmpty() ? "" : "a=" + authorizationId;
   126          String extensions = extensionsMessage();
   127          if (!extensions.isEmpty())
   128              extensions = SEPARATOR + extensions;
   129
   130          String message = String.format("n,%s,%sauth=Bearer %s%s%s%s", authzid,
   131                  SEPARATOR, tokenValue, extensions, SEPARATOR, SEPARATOR);
   132
   133          return message.getBytes(StandardCharsets.UTF_8);
   134      }
   135
   136      /**
   137       * Return the always non-null token value
   138       *
   139       * @return the always non-null token value
   140       */
   141      public String tokenValue() {
   142          return tokenValue;
   143      }
   144
   145      /**
   146       * Return the always non-null authorization ID
   147       *
   148       * @return the always non-null authorization ID
   149       */
   150      public String authorizationId() {
   151          return authorizationId;
   152      }
   153
   154      /**
   155       * Validates that the given extensions conform to the standard. They should also not contain the reserve key name {@link OAuthBearerClientInitialResponse#AUTH_KEY}
   156       *
   157       * @param extensions
   158       *            optional extensions to validate
   159       * @throws SaslException
   160       *             if any extension name or value fails to conform to the required
   161       *             regular expression as defined by the specification, or if the
   162       *             reserved {@code auth} appears as a key
   163       *
   164       * @see <a href="https://tools.ietf.org/html/rfc7628#section-3.1">RFC 7628,
   165       *  Section 3.1</a>
   166       */
