   177              if (!EXTENSION_KEY_PATTERN.matcher(extensionName).matches())
   178                  throw new SaslException("Extension name " + extensionName + " is invalid");
   179              if (!EXTENSION_VALUE_PATTERN.matcher(extensionValue).matches())
   180                  throw new SaslException("Extension value (" + extensionValue + ") for extension " + extensionName + " is invalid");
