   131              if (callback instanceof OAuthBearerValidatorCallback) {
   132                  OAuthBearerValidatorCallback validationCallback = (OAuthBearerValidatorCallback) callback;
   133                  try {
   134                      handleCallback(validationCallback);
   135                  } catch (OAuthBearerIllegalTokenException e) {
