   149      @Override
   150      public void close() {
   151          // empty
   152      }
   153
   154      private void handleCallback(OAuthBearerValidatorCallback callback) {
   155          String tokenValue = callback.tokenValue();
   156          if (tokenValue == null)
   157              throw new IllegalArgumentException("Callback missing required token value");
   158          String principalClaimName = principalClaimName();
   159          String scopeClaimName = scopeClaimName();
   160          List<String> requiredScope = requiredScope();
   161          int allowableClockSkewMs = allowableClockSkewMs();
