   166                  .validateClaimForExistenceAndType(unsecuredJwt, true, principalClaimName, String.class)
   167                  .throwExceptionIfFailed();
   168          OAuthBearerValidationUtils.validateIssuedAt(unsecuredJwt, false, now, allowableClockSkewMs)
   169                  .throwExceptionIfFailed();
   170          OAuthBearerValidationUtils.validateExpirationTime(unsecuredJwt, now, allowableClockSkewMs)
   171                  .throwExceptionIfFailed();
   172          OAuthBearerValidationUtils.validateTimeConsistency(unsecuredJwt).throwExceptionIfFailed();
   173          OAuthBearerValidationUtils.validateScope(unsecuredJwt, requiredScope).throwExceptionIfFailed();
