   177      }
   178
   179      private String principalClaimName() {
   180          String principalClaimNameValue = option(PRINCIPAL_CLAIM_NAME_OPTION);
   181          return Utils.isBlank(principalClaimNameValue) ? "sub" : principalClaimNameValue.trim();
   182      }
   183
   184      private String scopeClaimName() {
   185          String scopeClaimNameValue = option(SCOPE_CLAIM_NAME_OPTION);
   186          return Utils.isBlank(scopeClaimNameValue) ? "scope" : scopeClaimNameValue.trim();
   187      }
   188
   189      private List<String> requiredScope() {
   190          String requiredSpaceDelimitedScope = option(REQUIRED_SCOPE_OPTION);
   191          return Utils.isBlank(requiredSpaceDelimitedScope) ? Collections.emptyList() : OAuthBearerScopeUtils.parseScope(requiredSpaceDelimitedScope.trim());
   192      }
   193
   194      private int allowableClockSkewMs() {
   195          String allowableClockSkewMsValue = option(ALLOWABLE_CLOCK_SKEW_MILLIS_OPTION);
   196          int allowableClockSkewMs;
   197          try {
   198              allowableClockSkewMs = Utils.isBlank(allowableClockSkewMsValue) ? 0 : Integer.parseInt(allowableClockSkewMsValue.trim());
   199          } catch (NumberFormatException e) {
   200              throw new OAuthBearerConfigException(e.getMessage(), e);
   201          }
   202          if (allowableClockSkewMs < 0) {
   203              throw new OAuthBearerConfigException(
   204                      String.format("Allowable clock skew millis must not be negative: %s", allowableClockSkewMsValue));
   205          }
   206          return allowableClockSkewMs;
   207      }
   208
   209      private String option(String key) {
   210          if (!configured)
   211              throw new IllegalStateException("Callback handler not configured");
   212          return moduleOptions.get(Objects.requireNonNull(key));
   213      }
   214  }

